import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"1.7.见证","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/1.核心规则/1.7.见证.md","filePath":"1.基础规则/1.核心规则/1.7.见证.md"}'),d={name:"1.基础规则/1.核心规则/1.7.见证.md"};function p(_,a,l,i,b,c){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_1-7-见证",tabindex:"-1"},[s("1.7.见证 "),e("a",{class:"header-anchor",href:"#_1-7-见证","aria-label":'Permalink to "1.7.见证"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001")])])],-1),o('<h1 id="见证" tabindex="-1">见证 <a class="header-anchor" href="#见证" aria-label="Permalink to &quot;见证&quot;">​</a></h1><p>见证</p><p>见证我们所希望见证的一切，从出生到死亡，从海到海，从人间天国到黄金里。无论何时，见证不朽，传奇正盛。<br> 轮回者在建卡之初便将开始随着成长逐渐符合更多关于“见证”的标准，并获得更多的见证点数以代表已经被见证成长至一定地步。<br> 根据游戏的进程，更多的行为也会被纳入见证的记录之中。此外，每一场游戏结束时也可以将数点经验兑换为见证点数，每10点XP可以兑换为1点见证点数，根据人物游戏场次及等级进行换算：<br> 进行过一场及以上游戏的最高D级支线角色每场结束时可兑换一次（一次1点，下同）<br> 进行过三场及以上游戏的最高C级支线角色每场结束时可兑换二次<br> 进行过五场及以上游戏的最高B级支线角色每场结束时可兑换三次<br> 进行过七场及以上游戏的最高A级支线角色每场结束时可兑换四次<br> 进行过九场及以上游戏的最高S级支线角色每场结束时可兑换五次</p><p>D级角色每两场游戏结束获得1点见证点数<br> C级角色每两场游戏结束获得1点见证点数<br> B级角色每两场游戏结束获得3点见证点数<br> A级角色每两场游戏结束获得3点见证点数<br> S级角色每两场游戏结束获得5点见证点数</p><p>见证点数可以被使用以购买更多的见证强化，它们代表着对于技艺而言的精进，或者意味着跨越性的进步。也可以以转换为获得每1点10XP。</p><p>同时，在每场影片结束后，轮回者都可以选择三个最低等级的技能（如有多种，则选择其中一种），若其不足3，则均免费提升1级，若其大于3，则可以花费250分提升1级。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',8)])])}const m=r(d,[["render",p]]);export{f as __pageData,m as default};
